import "./dropdown-menu.css";

import { DropdownMenu } from "radix-ui";

import { DropdownMenuContext } from "./dropdown-menu.context";
import { dropdownMenuVariants } from "./dropdown-menu.variants";

export type DropdownMenuRootProps = React.ComponentProps<typeof DropdownMenu.Root>;

export const DropdownMenuRoot = (props: DropdownMenuRootProps) => {
  const slots = dropdownMenuVariants();

  return (
    <DropdownMenuContext value={{ slots }}>
      <DropdownMenu.Root {...props} />
    </DropdownMenuContext>
  );
};

import { DropdownMenu } from "radix-ui";

export type DropdownMenuTriggerProps = React.ComponentProps<typeof DropdownMenu.Trigger>;

export const DropdownMenuTrigger = (props: DropdownMenuTriggerProps) => {
  return <DropdownMenu.Trigger asChild {...props} />;
};

import { DropdownMenu } from "radix-ui";
import { cn } from "tailwind-variants";

import { useDropdownMenuContext } from "./dropdown-menu.context";

export type DropdownMenuContentProps = React.ComponentProps<typeof DropdownMenu.Content>;

export const DropdownMenuContent = ({
  className,
  sideOffset = 4,
  ...props
}: DropdownMenuContentProps) => {
  const { slots } = useDropdownMenuContext();

  return (
    <DropdownMenu.Portal>
      <DropdownMenu.Content
        className={cn(slots.content(), className)}
        sideOffset={sideOffset}
        {...props}
      />
    </DropdownMenu.Portal>
  );
};

