import { createContext, useContext } from "react";

import { dropdownMenuVariants } from "./dropdown-menu.variants";

export type DropdownMenuContext = {
  slots: ReturnType<typeof dropdownMenuVariants>;
};

export const DropdownMenuContext = createContext<DropdownMenuContext | null>(null);

export const useDropdownMenuContext = () => {
  const context = useContext(DropdownMenuContext);
  if (!context) {
    throw new Error("useDropdownMenuContext must be used within a DropdownMenu");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const dropdownMenuVariants = tv({
  slots: {
    checkbox: "dropdown-menu__checkbox-item",
    content: "dropdown-menu__content",
    indicator: "dropdown-menu__indicator",
    item: "dropdown-menu__item",
    label: "dropdown-menu__label",
    radio: "dropdown-menu__radio-item",
    separator: "dropdown-menu__separator",
    shortcut: "dropdown-menu__shortcut",
    subContent: "dropdown-menu__sub-content",
    subTrigger: "dropdown-menu__sub-trigger",
  },
});

export type DropdownMenuVariants = VariantProps<typeof dropdownMenuVariants>;

.dropdown-menu__content {
  @apply bg-popover text-popover-foreground z-50 min-w-[8rem] overflow-hidden rounded-md border p-1 shadow-md;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }

  &[data-side="bottom"] {
    @apply slide-in-from-top-2;
  }

  &[data-side="left"] {
    @apply slide-in-from-right-2;
  }

  &[data-side="right"] {
    @apply slide-in-from-left-2;
  }

  &[data-side="top"] {
    @apply slide-in-from-bottom-2;
  }
}

.dropdown-menu__item {
  @apply relative flex cursor-default items-center rounded-sm px-2 py-1.5 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.dropdown-menu__checkbox-item {
  @apply relative flex cursor-default items-center rounded-sm py-1.5 pr-2 pl-8 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.dropdown-menu__radio-item {
  @apply relative flex cursor-default items-center rounded-sm py-1.5 pr-2 pl-8 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-disabled] {
    @apply pointer-events-none opacity-50;
  }
}

.dropdown-menu__indicator {
  @apply absolute left-2 inline-flex items-center justify-center;

  & svg {
    @apply size-3.5;
  }
}

.dropdown-menu__label {
  @apply text-muted-foreground px-2 py-1.5 text-xs font-semibold;
}

.dropdown-menu__separator {
  @apply bg-border -mx-1 my-1 h-px;
}

.dropdown-menu__shortcut {
  @apply text-muted-foreground ml-auto text-xs tracking-widest;
}

.dropdown-menu__sub-trigger {
  @apply relative flex cursor-default items-center rounded-sm px-2 py-1.5 text-sm outline-none select-none;

  &[data-highlighted] {
    @apply bg-accent text-accent-foreground;
  }

  &[data-state="open"] {
    @apply bg-accent text-accent-foreground;
  }
}

.dropdown-menu__sub-content {
  @apply bg-popover text-popover-foreground z-50 min-w-[8rem] overflow-hidden rounded-md border p-1 shadow-lg;

  &[data-state="open"] {
    @apply animate-in fade-in-0 zoom-in-95;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out-0 zoom-out-95;
  }

  &[data-side="bottom"] {
    @apply slide-in-from-top-2;
  }

  &[data-side="left"] {
    @apply slide-in-from-right-2;
  }

  &[data-side="right"] {
    @apply slide-in-from-left-2;
  }

  &[data-side="top"] {
    @apply slide-in-from-bottom-2;
  }
}

import { DropdownMenuCheckboxItem } from "./dropdown-menu-checkbox-item";
import { DropdownMenuContent } from "./dropdown-menu-content";
import { DropdownMenuItem } from "./dropdown-menu-item";
import { DropdownMenuLabel } from "./dropdown-menu-label";
import { DropdownMenuRadioItem } from "./dropdown-menu-radio-item";
import { DropdownMenuRoot } from "./dropdown-menu-root";
import { DropdownMenuSeparator } from "./dropdown-menu-separator";
import { DropdownMenuShortcut } from "./dropdown-menu-shortcut";
import {
  DropdownMenuSub,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
} from "./dropdown-menu-sub";
import { DropdownMenuTrigger } from "./dropdown-menu-trigger";

export const DropdownMenu = {
  CheckboxItem: DropdownMenuCheckboxItem,
  Content: DropdownMenuContent,
  Item: DropdownMenuItem,
  Label: DropdownMenuLabel,
  RadioItem: DropdownMenuRadioItem,
  Root: DropdownMenuRoot,
  Separator: DropdownMenuSeparator,
  Shortcut: DropdownMenuShortcut,
  Sub: DropdownMenuSub,
  SubContent: DropdownMenuSubContent,
  SubTrigger: DropdownMenuSubTrigger,
  Trigger: DropdownMenuTrigger,
};

export {
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuRadioItem,
  DropdownMenuRoot,
  DropdownMenuSeparator,
  DropdownMenuShortcut,
  DropdownMenuSub,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
  DropdownMenuTrigger,
};

export type { DropdownMenuCheckboxItemProps } from "./dropdown-menu-checkbox-item";

export type { DropdownMenuContentProps } from "./dropdown-menu-content";

export type { DropdownMenuItemProps } from "./dropdown-menu-item";
export type { DropdownMenuLabelProps } from "./dropdown-menu-label";
export type { DropdownMenuRadioItemProps } from "./dropdown-menu-radio-item";
export type { DropdownMenuRootProps } from "./dropdown-menu-root";
export type { DropdownMenuSeparatorProps } from "./dropdown-menu-separator";
export type { DropdownMenuShortcutProps } from "./dropdown-menu-shortcut";
export type {
  DropdownMenuSubContentProps,
  DropdownMenuSubProps,
  DropdownMenuSubTriggerProps,
} from "./dropdown-menu-sub";
export type { DropdownMenuTriggerProps } from "./dropdown-menu-trigger";
export { DropdownMenuContext, useDropdownMenuContext } from "./dropdown-menu.context";
export { type DropdownMenuVariants, dropdownMenuVariants } from "./dropdown-menu.variants";
